import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Button, Card, Badge, Avatar, icon } from 'decantr/components';

code.example:
function ContentFeed({ posts = [], creator, userTier = null, onUnlock }) {
  const { div, h3, p, span, img, video, audio, a } = tags;
  const [filter, setFilter] = createSignal('all');

  const filtered = () => filter() === 'all' ? posts : posts.filter(p => p.type === filter());
  const canView = (post) => !post.requiredTier || (userTier && userTier.level >= post.requiredTier.level);

  const typeIcon = { image: 'image', video: 'video', audio: 'music', text: 'file-text', link: 'link' };

  return div({ class: css('_flex _col _gap6 _maxw[720px] _mx[auto]') },
    div({ class: css('_flex _gap2 _overflowX[auto] _pb2') },
      ...['all', 'image', 'video', 'audio', 'text'].map(type =>
        Button({
          variant: filter() === type ? 'primary' : 'outline',
          size: 'sm',
          onclick: () => setFilter(type)
        },
          icon(type === 'all' ? 'grid' : typeIcon[type], { size: '14', class: css('_mr1') }),
          type.charAt(0).toUpperCase() + type.slice(1)
        )
      )
    ),
    ...filtered().map(post =>
      Card({ class: css('studio-card _overflow[hidden]') },
        div({ class: css('_flex _aic _gap3 _p4 _borderB') },
          Avatar({ src: creator.avatar, name: creator.name, size: 'sm' }),
          div({ class: css('_flex1') },
            span({ class: css('_fontmedium') }, creator.name),
            span({ class: css('_textsm _fgmuted _ml2') }, new Date(post.createdAt).toLocaleDateString())
          ),
          post.requiredTier ? Badge({ variant: 'secondary', size: 'sm' },
            icon('lock', { size: '12', class: css('_mr1') }), post.requiredTier.name
          ) : null
        ),
        canView(post) ? [
          post.type === 'image' && post.media ? div({ class: css('_aspect[16/9]') },
            img({ src: post.media, class: css('_wfull _hfull _objcover') })
          ) : null,
          post.type === 'video' && post.media ? div({ class: css('_aspect[16/9] _bgblack') },
            video({ src: post.media, controls: true, class: css('_wfull _hfull') })
          ) : null,
          post.type === 'audio' && post.media ? div({ class: css('_p4 _bgmuted/5') },
            audio({ src: post.media, controls: true, class: css('_wfull') })
          ) : null,
          div({ class: css('_p4') },
            post.title ? h3({ class: css('_fontmedium _mb2') }, post.title) : null,
            p({ class: css('_fgmuted _whitespace[pre-wrap]') }, post.content)
          )
        ] : div({ class: css('_relative') },
          div({ class: css('_aspect[16/9] _bgmuted/10') },
            post.previewImage ? img({ src: post.previewImage, class: css('_wfull _hfull _objcover _blur[8px]') }) : null
          ),
          div({ class: css('_absolute _inset0 studio-gate-blur _flex _col _center _p6 _tc') },
            div({ class: css('_w16 _h16 _r[50%] _bgbg _flex _center _shadow _mb4') },
              icon('lock', { size: '24', class: css('_fgmuted') })
            ),
            p({ class: css('_fontmedium _mb2') }, 'Unlock this post'),
            p({ class: css('_textsm _fgmuted _mb4') }, 'Subscribe to ', post.requiredTier.name, ' or higher'),
            Button({ variant: 'primary', onclick: () => onUnlock?.(post) }, 'Subscribe to Unlock')
          )
        ),
        div({ class: css('_flex _jcsb _aic _p4 _borderT') },
          div({ class: css('_flex _gap4') },
            Button({ variant: 'ghost', size: 'sm', class: css('_flex _aic _gap1') },
              icon('heart', { size: '18' }), post.likes || 0
            ),
            Button({ variant: 'ghost', size: 'sm', class: css('_flex _aic _gap1') },
              icon('message-circle', { size: '18' }), post.comments || 0
            ),
            Button({ variant: 'ghost', size: 'sm' }, icon('share-2', { size: '18' }))
          ),
          post.downloadable && canView(post) ? Button({ variant: 'ghost', size: 'sm' },
            icon('download', { size: '18' })
          ) : null
        )
      )
    ),
    filtered().length > 10 ? div({ class: css('_flex _jcc') },
      Button({ variant: 'outline' }, 'Load More')
    ) : null,
    filtered().length === 0 ? div({ class: css('_py16 _tc _fgmuted') },
      icon('inbox', { size: '48', class: css('_mb4 _fgmuted/50') }),
      p({}, 'No content yet')
    ) : null
  );
}

