function ContentFeedGrid({ posts, onSelect }) {
  const { div, img, span } = tags;

  return div({ class: css('_grid _gc2 _md:gc3 _gap4') },
    ...posts.map(post =>
      Card({ class: css('studio-card _overflow[hidden] _cursor[pointer]'), onclick: () => onSelect?.(post) },
        div({ class: css('_aspect[1] _relative _bgmuted/10') },
          post.thumbnail ? img({ src: post.thumbnail, class: css('_wfull _hfull _objcover') }) : null,
          post.locked ? div({ class: css('_absolute _inset0 studio-gate-blur _flex _center') },
            icon('lock', { size: '24', class: css('_fgmuted') })
          ) : null
        )
      )
    )
  );
}

