function ContentFeedCompact({ posts, onSelect }) {
  const { div, span, img } = tags;
  const typeIcon = { image: 'image', video: 'video', audio: 'music', text: 'file-text' };

  return div({ class: css('_flex _col _gap2') },
    ...posts.map(post =>
      Card({ class: css('studio-card _p3 _flex _aic _gap3 _cursor[pointer]'), onclick: () => onSelect?.(post) },
        div({ class: css('_w12 _h12 _r2 _bgmuted/10 _flex _center _flex-shrink-0') },
          post.thumbnail ? img({ src: post.thumbnail, class: css('_wfull _hfull _objcover _r2') }) :
            icon(typeIcon[post.type], { size: '20', class: css('_fgmuted') })
        ),
        div({ class: css('_flex1 _minw0') },
          span({ class: css('_fontmedium _truncate _block') }, post.title || 'Untitled'),
          span({ class: css('_textsm _fgmuted') }, new Date(post.createdAt).toLocaleDateString())
        ),
        post.locked ? icon('lock', { size: '16', class: css('_fgmuted') }) : null
      )
    )
  );
}

